// Validate and normalize the incoming email
const body = $json.body || $json;
const email = (body.email || '').trim().toLowerCase();

if (!email || !email.includes('@') || !email.includes('.')) {
  throw new Error('Invalid or missing email: ' + email);
}

return { json: { ...body, email } };

// Lead Scoring Logic — uses Lusha simplified output fields
const lusha = $json;
const form = $('Validate Email').first().json;
let score = 0;
const reasons = [];

// Seniority scoring
const seniority = (lusha.seniority || '').toLowerCase();
if (['c-suite', 'cxo', 'founder', 'owner'].some(s => seniority.includes(s))) {
  score += 30; reasons.push('C-Suite/Founder (+30)');
} else if (seniority.includes('vp') || seniority.includes('vice president')) {
  score += 25; reasons.push('VP level (+25)');
} else if (seniority.includes('director')) {
  score += 20; reasons.push('Director level (+20)');
} else if (seniority.includes('manager')) {
  score += 10; reasons.push('Manager level (+10)');
}

// Company size scoring (companySize is an array like [51, 200])
const empMax = Array.isArray(lusha.companySize) ? lusha.companySize[1] : 0;
if (empMax >= 1000) {
  score += 25; reasons.push('Enterprise 1000+ (+25)');
} else if (empMax >= 200) {
  score += 20; reasons.push('Mid-market 200+ (+20)');
} else if (empMax >= 50) {
  score += 10; reasons.push('SMB 50+ (+10)');
}

// Target industry (customize this list!)
const targetIndustries = ['technology', 'software', 'saas', 'fintech', 'financial services'];
const industry = (lusha.companyMainIndustry || '').toLowerCase();
if (targetIndustries.some(ti => industry.includes(ti))) {
  score += 15; reasons.push('Target industry (+15)');
}

// Data quality scoring
if (lusha.primaryPhone) { score += 10; reasons.push('Has direct phone (+10)'); }
if (lusha.primaryEmail) { score += 5; reasons.push('Has verified email (+5)'); }

// Determine tier
let tier = 'cold';
if (score >= 60) tier = 'hot';
else if (score >= 35) tier = 'warm';

return {
  json: {
    firstName: form.firstName || lusha.firstName,
    lastName: form.lastName || lusha.lastName,
    email: form.email,
    verifiedEmail: lusha.primaryEmail,
    phone: lusha.primaryPhone,
    jobTitle: lusha.jobTitle,
    seniority: lusha.seniority,
    company: lusha.companyName,
    companyDomain: lusha.companyDomain,
    companySize: empMax,
    industry: lusha.companyMainIndustry,
    linkedinUrl: lusha.linkedinProfile || '',
    leadScore: score,
    leadTier: tier,
    scoreReasons: reasons,
    enrichedAt: new Date().toISOString()
  }
};

